code.Java:
import java.io.*;
import java.util.*;

public class Main {
    private static final double PI = Math.acos(-1.0);
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder sb = new StringBuilder();
        for (int t = 0; t < T; ++t) {
            String shape = br.readLine().trim();
            if (shape.equals("circle")) {
                double r = Double.parseDouble(br.readLine().trim());
                double area = PI * r * r;
                sb.append(String.format(java.util.Locale.US, "%.2f", area)).append('\n');
            } else if (shape.equals("rectangle")) {
                String[] parts = br.readLine().trim().split(" ");
                double l = Double.parseDouble(parts[0]);
                double w = Double.parseDouble(parts[1]);
                double area = l * w;
                sb.append(String.format(java.util.Locale.US, "%.2f", area)).append('\n');
            }
        }
        System.out.print(sb.toString());
    }
}

code.Python3:
#!/usr/bin/env python3
import sys, math

def main():
    data = sys.stdin.read().strip().splitlines()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        shape = next(it).strip()
        if shape == 'circle':
            r = float(next(it).strip())
            area = math.pi * r * r
        elif shape == 'rectangle':
            l, w = map(float, next(it).split())
            area = l * w
        else:
            continue
        out.append(f"{area:.2f}")
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

